# step_definitions/expense_categorisation_steps.py
from pytest_bdd import given, when, then, parsers
from app.agent import categorise_expense
from tests.fixtures import load_vcr_cassette

@given(parsers.parse("an expense of GBP {amount:f} with description {description!r}"))
def expense_submitted(context, amount, description):
    context['expense'] = {'amount': amount, 'currency': 'GBP', 'description': description}

@when("I submit the expense for categorisation")
def submit_expense(context):
    if context.get('use_cassette'):
        with load_vcr_cassette('expense_categorisation'):
            context['result'] = categorise_expense(context['expense'])
    else:
        context['result'] = categorise_expense(context['expense'])

@then(parsers.parse('the agent assigns the category {expected_category!r}'))
def assert_category(context, expected_category):
    actual = context['result'].get('category')
    assert actual == expected_category, (
        f"Expected category '{expected_category}', got '{actual}'"
    )

@then(parsers.parse("the confidence score exceeds {threshold:f}"))
def assert_confidence(context, threshold):
    actual = context['result'].get('confidence', 0)
    assert actual > threshold, (
        f"Expected confidence > {threshold}, got {actual}"
    )

@then("no manual review flag is raised")
def assert_no_review_flag(context):
    assert not context['result'].get('review_required', False)
